const proj4 = require('../dist/proj4-src.js');

const input = [-8895604.157333, 4447802.078667];

function makeWkt(longitudeOfCenter) {
  return `PROJCS["unnamed",GEOGCS["Unknown datum based upon the custom spheroid",DATUM["Not specified (based on custom spheroid)",SPHEROID["Custom spheroid",6371007.181,0]],PRIMEM["Greenwich",0],UNIT["degree",0.0174532925199433,AUTHORITY["EPSG","9122"]]],PROJECTION["Sinusoidal"],PARAMETER["longitude_of_center",${longitudeOfCenter}],PARAMETER["false_easting",0],PARAMETER["false_northing",0],UNIT["Meter",1],AXIS["Easting",EAST],AXIS["Northing",NORTH]]`;
}

function makeProj4(lon0) {
  return `+proj=sinu +lon_0=${lon0} +x_0=0 +y_0=0 +R=6371007.181 +units=m +no_defs +type=crs`;
}

function assertClosePair(actual, expected, label, epsilon = 1e-9) {
  if (!actual.every(Number.isFinite)) {
    throw new Error(`${label} contains non-finite coordinates: ${actual}`);
  }
  if (Math.abs(actual[0] - expected[0]) > epsilon || Math.abs(actual[1] - expected[1]) > epsilon) {
    throw new Error(`${label} expected ${expected}, received ${actual}`);
  }
}

for (const lon0 of [0, 10]) {
  const wkt = makeWkt(lon0);
  const proj = makeProj4(lon0);
  const wktResult = proj4(wkt, 'EPSG:4326').forward(input);
  const projResult = proj4(proj, 'EPSG:4326').forward(input);
  console.log({ lon0, wktResult, projResult });
  assertClosePair(wktResult, projResult, `direct WKT lon0=${lon0}`);
}

proj4.defs('MODIS_SINU_REPRO', makeWkt(0));
assertClosePair(
  proj4('MODIS_SINU_REPRO', 'EPSG:4326').forward(input),
  proj4(makeProj4(0), 'EPSG:4326').forward(input),
